// @ts-nocheck
export function getStats({glucose:e=[],insulin:t=[],meals:r=[],exercises:l=[],preferences:n={}}){const a=Number(n.targetMin??3.9),u=Number(n.targetMax??10),o=e.length>0?e[e.length-1]:null,i=r.reduce((e,t)=>e+Number(t.carbs??t.carbsEstimate??0),0),s=t.reduce((e,t)=>e+Number(t.dose??t.units??0),0),c=e.map(e=>Number(e.val??e.value)).filter(e=>Number.isFinite(e)),f=c.length?c.reduce((e,t)=>e+t,0)/c.length:0,d=c.length?f.toFixed(1):"--",g=c.filter(e=>e>=a&&e<=u).length,p=l.reduce((e,t)=>e+Number(t.duration??t.durationMinutes??0),0),m=t.filter(e=>(e.type??e.insulinType)==="Novorapid").reduce((e,t)=>e+Number(t.dose??t.units??0),0),h=t.filter(e=>(e.type??e.insulinType)==="Lantus").reduce((e,t)=>e+Number(t.dose??t.units??0),0),v=c.filter(e=>e<a).length,y=c.filter(e=>e>u).length,b=!Number.isFinite(Number(f))||Number(f)<=0?null:((Number(f)+2.59)/1.59).toFixed(1);return{latestG:o,totalCarbs:i,totalInsulin:s,avgG:d,tir:c.length?Math.round(g/c.length*100):0,activeMinutes:p,novorapid:m,lantus:h,low:v,high:y,hba1c:b}}
